623	    // --- Transact Operations ---
624	
625	    public void transactWriteItems(List<JsonNode> transactItems, String region) {
626	        // First pass: evaluate all conditions and collect failures
627	        List<String> cancellationReasons = new ArrayList<>();
628	        boolean hasFailed = false;
629	
630	        for (JsonNode transactItem : transactItems) {
631	            String failReason = evaluateTransactCondition(transactItem, region);
632	            if (failReason != null) {
633	                hasFailed = true;
634	                cancellationReasons.add(failReason);
635	            } else {
636	                cancellationReasons.add("");
637	            }
638	        }
639	
640	        if (hasFailed) {
641	            throw new TransactionCanceledException(cancellationReasons);
642	        }
643	
644	        // Second pass: apply all writes
645	        for (JsonNode transactItem : transactItems) {
646	            if (transactItem.has("Put")) {
647	                JsonNode put = transactItem.get("Put");
648	                String tableName = put.path("TableName").asText();
649	                JsonNode item = put.get("Item");
650	                putItem(tableName, item, region);
651	            } else if (transactItem.has("Delete")) {
652	                JsonNode del = transactItem.get("Delete");
653	                String tableName = del.path("TableName").asText();
654	                JsonNode key = del.get("Key");
655	                deleteItem(tableName, key, region);
656	            } else if (transactItem.has("Update")) {
657	                JsonNode upd = transactItem.get("Update");
658	                String tableName = upd.path("TableName").asText();
659	                JsonNode key = upd.get("Key");
660	                String updateExpression = upd.has("UpdateExpression") ? upd.get("UpdateExpression").asText() : null;
661	                JsonNode exprAttrNames = upd.has("ExpressionAttributeNames") ? upd.get("ExpressionAttributeNames") : null;
662	                JsonNode exprAttrValues = upd.has("ExpressionAttributeValues") ? upd.get("ExpressionAttributeValues") : null;
663	                updateItem(tableName, key, null, updateExpression, exprAttrNames, exprAttrValues,
664	                           "NONE", null, region);
665	            }
666	            // ConditionCheck-only items are handled in the first pass only
667	        }
668	    }
669	
670	    private String evaluateTransactCondition(JsonNode transactItem, String region) {
671	        JsonNode target;
672	        if (transactItem.has("Put")) {
673	            target = transactItem.get("Put");
674	        } else if (transactItem.has("Delete")) {
675	            target = transactItem.get("Delete");
676	        } else if (transactItem.has("Update")) {
677	            target = transactItem.get("Update");
678	        } else if (transactItem.has("ConditionCheck")) {
679	            target = transactItem.get("ConditionCheck");
680	        } else {
681	            return null;
682	        }
683	
684	        String conditionExpression = target.has("ConditionExpression")
685	                ? target.get("ConditionExpression").asText() : null;
686	        if (conditionExpression == null) {
687	            return null;
688	        }
689	
690	        String tableName = target.path("TableName").asText();
691	        JsonNode key = transactItem.has("Put") ? target.get("Item") : target.get("Key");
692	        JsonNode exprAttrNames = target.has("ExpressionAttributeNames") ? target.get("ExpressionAttributeNames") : null;
693	        JsonNode exprAttrValues = target.has("ExpressionAttributeValues") ? target.get("ExpressionAttributeValues") : null;
694	
695	        String storageKey = regionKey(region, tableName);
696	        TableDefinition table = tableStore.get(storageKey)
697	                .orElseThrow(() -> resourceNotFoundException(tableName));
698	
699	        String itemKey = buildItemKey(table, key);
700	        var tableItems = itemsByTable.get(storageKey);
701	        JsonNode existing = tableItems != null ? tableItems.get(itemKey) : null;
702	
703	        try {
704	            evaluateCondition(existing, conditionExpression, exprAttrNames, exprAttrValues);
705	            return null;
706	        } catch (AwsException e) {
707	            return e.getMessage();
708	        }
709	    }
