1070	    /**
1071	     * Implements DynamoDB ADD operation semantics:
1072	     * - For numbers (N): adds the value to the existing number, or sets it if attribute doesn't exist
1073	     * - For sets (SS, NS, BS): adds elements to the existing set, or creates the set if it doesn't exist
1074	     */
1075	    private JsonNode applyAddOperation(JsonNode existingValue, JsonNode addValue) {
1076	        ObjectNode result = com.fasterxml.jackson.databind.node.JsonNodeFactory.instance.objectNode();
1077	
1078	        // Handle number addition
1079	        if (addValue.has("N")) {
1080	            String addNumStr = addValue.get("N").asText();
1081	            if (existingValue == null || !existingValue.has("N")) {
1082	                // Attribute doesn't exist — set to the add value
1083	                return addValue;
1084	            }
1085	            // Add the numbers
1086	            String existingNumStr = existingValue.get("N").asText();
1087	            try {
1088	                java.math.BigDecimal existingNum = new java.math.BigDecimal(existingNumStr);
1089	                java.math.BigDecimal addNum = new java.math.BigDecimal(addNumStr);
1090	                result.put("N", existingNum.add(addNum).toPlainString());
1091	                return result;
1092	            } catch (NumberFormatException e) {
1093	                // Fall back to just setting the value
1094	                return addValue;
1095	            }
1096	        }
1097	
1098	        // Handle string set (SS) addition
1099	        if (addValue.has("SS")) {
1100	            if (existingValue == null || !existingValue.has("SS")) {
1101	                return addValue;
1102	            }
1103	            java.util.Set<String> combined = new java.util.LinkedHashSet<>();
1104	            existingValue.get("SS").forEach(n -> combined.add(n.asText()));
1105	            addValue.get("SS").forEach(n -> combined.add(n.asText()));
1106	            var arrayNode = result.putArray("SS");
1107	            combined.forEach(arrayNode::add);
1108	            return result;
1109	        }
1110	
1111	        // Handle number set (NS) addition
1112	        if (addValue.has("NS")) {
1113	            if (existingValue == null || !existingValue.has("NS")) {
1114	                return addValue;
1115	            }
1116	            java.util.Set<String> combined = new java.util.LinkedHashSet<>();
1117	            existingValue.get("NS").forEach(n -> combined.add(n.asText()));
1118	            addValue.get("NS").forEach(n -> combined.add(n.asText()));
1119	            var arrayNode = result.putArray("NS");
1120	            combined.forEach(arrayNode::add);
1121	            return result;
1122	        }
1123	
1124	        // Handle binary set (BS) addition
1125	        if (addValue.has("BS")) {
1126	            if (existingValue == null || !existingValue.has("BS")) {
1127	                return addValue;
1128	            }
1129	            java.util.Set<String> combined = new java.util.LinkedHashSet<>();
1130	            existingValue.get("BS").forEach(n -> combined.add(n.asText()));
1131	            addValue.get("BS").forEach(n -> combined.add(n.asText()));
1132	            var arrayNode = result.putArray("BS");
1133	            combined.forEach(arrayNode::add);
1134	            return result;
1135	        }
1136	
1137	        // Unsupported type for ADD — just set the value
1138	        return addValue;
1139	    }
