        u1.set("bins", binarySetAttributeValue("AQID", "BAUG"));  // base64 for [1,2,3] and [4,5,6]
        service.putItem("Users", u1);

        ObjectNode u2 = item("userId", "u2");
        u2.set("bins", binarySetAttributeValue("BwgJ"));
