    String streamArn = table.getStreamArn();
    if (streamArn == null || streamArn.isBlank()) {
        return null;
    }

    String key = streamKey(region, table.getTableName());
    StreamDescription existing = streams.get(key);
    if (existing != null) {
        records.computeIfAbsent(existing.getStreamArn(), ignored -> new ConcurrentLinkedDeque<>());
